code = """import json
import re

# Read books data with publication years
books_file_path = locals()['var_functions.query_db:24']
with open(books_file_path, 'r') as f:
    books_data = json.load(f)

# Extract publication year from details
books_with_year = []
for book in books_data:
    details = book.get('details', '')
    year_matches = re.findall(r'(?:released|published) (?:on |in |by )[^,]*,? [^\d]*(\d{4})', details, re.IGNORECASE)
    
    if not year_matches:
        year_matches = re.findall(r'(\b(19|20)\d{2}\b)', details)
        if year_matches:
            year_matches = [m[0] for m in year_matches]
    
    if year_matches:
        year = int(year_matches[0])
        if 1900 <= year <= 2023:
            books_with_year.append({
                'book_id': book['book_id'],
                'year': year,
                'decade': (year // 10) * 10
            })

# Load all reviews
reviews_file_path = locals()['var_functions.query_db:28']
with open(reviews_file_path, 'r') as f:
    reviews_data = json.load(f)

# Create book_id from purchase_id (convert purchaseid_X to bookid_X)
for review in reviews_data:
    purchase_id = review['purchase_id']
    if purchase_id.startswith('purchaseid_'):
        review['book_id'] = 'bookid_' + purchase_id.split('_')[1]
    else:
        review['book_id'] = purchase_id

# Join books with reviews
books_dict = {b['book_id']: b for b in books_with_year}

# Aggregate ratings by book and decade
book_ratings = {}
for review in reviews_data:
    book_id = review['book_id']
    if book_id in books_dict:
        rating = float(review['rating'])
        book_info = books_dict[book_id]
        decade = book_info['decade']
        
        if book_id not in book_ratings:
            book_ratings[book_id] = {
                'ratings': [],
                'decade': decade,
                'year': book_info['year']
            }
        book_ratings[book_id]['ratings'].append(rating)

# Calculate average rating per book
book_avg_ratings = []
for book_id, data in book_ratings.items():
    avg_rating = sum(data['ratings']) / len(data['ratings'])
    book_avg_ratings.append({
        'book_id': book_id,
        'decade': data['decade'],
        'year': data['year'],
        'avg_rating': avg_rating,
        'rating_count': len(data['ratings'])
    })

# Aggregate by decade
decade_stats = {}
for book in book_avg_ratings:
    decade = book['decade']
    if decade not in decade_stats:
        decade_stats[decade] = {
            'books': [],
            'ratings': []
        }
    decade_stats[decade]['books'].append(book['book_id'])
    decade_stats[decade]['ratings'].append(book['avg_rating'])

# Calculate average rating per decade and filter by min 10 books
decade_averages = []
for decade, stats in decade_stats.items():
    if len(stats['books']) >= 10:
        avg_rating = sum(stats['ratings']) / len(stats['ratings'])
        decade_averages.append({
            'decade': f"{decade}s",
            'avg_rating': round(avg_rating, 3),
            'book_count': len(stats['books'])
        })

# Sort by average rating descending
decade_averages.sort(key=lambda x: x['avg_rating'], reverse=True)

result = {
    'decades_with_min_books': len(decade_averages),
    'decade_rankings': decade_averages[:10],
    'top_decade': decade_averages[0] if decade_averages else None
}

print('__RESULT__:')
print(json.dumps(result))"""

